previewCss:
.darma-loader-uiverse-crimson-shine-emblem { position: relative; width: 160px; height: 160px; }
.darma-loader-uiverse-crimson-shine-emblem__pattern-1 {
  position: absolute;
  background-color: var(--loader-color, #ff4c5a);
  width: 160px;
  height: 160px;
  clip-path: polygon(0 10%, 70% 90%, 40% 90%, 0 45%);
  overflow: hidden;
}
.darma-loader-uiverse-crimson-shine-emblem__pattern-2 {
  position: absolute;
  background-color: var(--loader-color, #ff4c5a);
  width: 176px;
  height: 152px;
  clip-path: polygon(100% 10%, 100% 45%, 83% 65%, 55% 65%);
}
.darma-loader-uiverse-crimson-shine-emblem__pattern-1-shade {
  position: absolute;
  opacity: .75;
  background-color: white;
  width: 18px;
  height: 160px;
  animation: darma-loader-uiverse-crimson-shine-emblem-crimsonShine 1.1s infinite;
}
@keyframes darma-loader-uiverse-crimson-shine-emblem-crimsonShine { from { transform: translateX(-22px); } to { transform: translateX(130px); } }

